// invoiceStatusBadgeClass maps invoice status to a small inline badge style.
func invoiceStatusBadgeClass(s models.InvoiceStatus) string {
	base := "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch s {
	case models.InvoiceStatusDraft:
		return base + "bg-background text-text-muted border border-border"
	case models.InvoiceStatusIssued:
		return base + "bg-primary-soft text-primary border border-primary-soft"
	case models.InvoiceStatusSent:
		return base + "bg-primary-soft text-primary border border-primary-soft"
	case models.InvoiceStatusPartiallyPaid:
		return base + "bg-warning-soft text-warning border border-warning-soft"
	case models.InvoiceStatusPaid:
		return base + "bg-success-soft text-success-hover border border-success-border"
	case models.InvoiceStatusOverdue:
		return base + "bg-danger-soft text-danger border border-danger-soft"
	case models.InvoiceStatusVoided:
		return base + "bg-background text-text-muted2 border border-border line-through"
	default:
		return base + "bg-background text-text-muted border border-border"
	}
}

